import type { AnalysisRequest, InterviewMessageRequest } from "../types";

export function buildAnalysisPrompt(input: Required<AnalysisRequest>) {
  return [
    {
      role: "system" as const,
      content:
        "你是资深求职面试教练。你必须只输出 JSON，不要 Markdown。请基于简历、JD 和岗位方向，生成结构化面试准备分析。",
    },
    {
      role: "user" as const,
      content: `
岗位方向：${input.roleTrack}

简历内容：
${input.resumeText || "未提供"}

JD 内容：
${input.jdText || "未提供"}

请输出 JSON，字段必须为：
{
  "matchScore": number,
  "roleTrack": string,
  "summary": string,
  "strengths": string[],
  "weaknesses": string[],
  "predictedQuestions": string[],
  "trainingPlan": [{ "title": string, "reason": string }]
}
要求：
- matchScore 为 0-100。
- strengths 3-5 条。
- weaknesses 3-5 条。
- predictedQuestions 4-6 条，要像真实面试官会追问的问题。
- trainingPlan 2-4 条，要可执行。
`,
    },
  ];
}

export function buildInterviewPrompt(input: Required<Omit<InterviewMessageRequest, "sessionId">>) {
  const history = input.history.map((turn) => `${turn.role === "ai" ? "AI 面试官" : "候选人"}：${turn.content}`).join("\n");

  return [
    {
      role: "system" as const,
      content:
        "你是严格但专业的 AI 面试官兼教练。你必须只输出 JSON，不要 Markdown。你会评价候选人当前回答，并给出下一道追问。",
    },
    {
      role: "user" as const,
      content: `
岗位方向：${input.roleTrack}

简历内容：
${input.resumeText || "未提供"}

JD 内容：
${input.jdText || "未提供"}

分析报告：
${JSON.stringify(input.analysis)}

历史对话：
${history || "暂无"}

候选人刚刚回答：
${input.answer || "候选人尚未回答，这是第一轮。"}

请输出 JSON：
{
  "evaluation": {
    "score": number,
    "summary": string,
    "strengths": string[],
    "improvements": string[],
    "rewrittenAnswer": string
  },
  "nextQuestion": string,
  "testedSkill": string
}
要求：
- score 为 0-100。
- rewrittenAnswer 使用 STAR 或“结论-证据-指标-反思”结构。
- nextQuestion 必须基于候选人的回答继续追问，不要泛泛而谈。
`,
    },
  ];
}
